// Detectar portal usando JSON.stringify (funciona con cualquier tipo de dato en "from")
const allFromData = JSON.stringify({
  from: $json.from,
  headerFrom: ($json.headers && ($json.headers.from || $json.headers.From)) || '',
  subject: $json.subject || ''
}).toLowerCase();

let fuente = 'Desconocido';
if (allFromData.includes('fotocasa')) fuente = 'Fotocasa';
else if (allFromData.includes('idealista')) fuente = 'Idealista';
else if (allFromData.includes('yaencontre')) fuente = 'Ya encontré';

// Contenido del email
const textContent = String($json.text || '');
const htmlContent = String($json.html || '');

let body = textContent;
if (body.trim().length < 30) {
  body = htmlContent
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&#39;/g, "'")
    .replace(/\s+/g, '\n');
}

body = body.replace(/\(\s*https?:\/\/[^)]+\)/g, '').replace(/https?:\/\/\S+/g, '');

// Fecha en español
const meses = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];
const dateObj = new Date($json.date || '');
const fecha = !isNaN(dateObj.getTime())
  ? dateObj.getDate() + ' de ' + meses[dateObj.getMonth()] + ' ' + dateObj.getFullYear()
  : 'Fecha desconocida';

const pisos = [];

if (fuente === 'Fotocasa') {
  const lines = body.split('\n').map(l => l.trim()).filter(Boolean);
  for (let i = 0; i < lines.length; i++) {
    if (/^\d[\d.]+\s*€\s*$/.test(lines[i])) {
      const precio = lines[i].trim();
      for (let j = i+1; j < Math.min(i+6, lines.length); j++) {
        const m = lines[j].match(/^piso\s*[·•]\s*(.+)$/i);
        if (m) { pisos.push({ titulo: m[1].trim(), precio, fuente, fecha }); break; }
      }
    }
  }
}

if (fuente === 'Ya encontré') {
  const flat = body.replace(/\n/g, ' ');
  const re = /Piso en venta en ([^,.]+)/gi;
  const pr = /(\d[\d.]+)\s*€/g;
  const titles = [], prices = [];
  let m;
  while ((m = re.exec(flat)) !== null) titles.push(m[1].trim());
  while ((m = pr.exec(flat)) !== null) prices.push(m[1] + ' €');
  titles.forEach((t, i) => pisos.push({ titulo: t, precio: prices[i] || 'N/D', fuente, fecha }));
}

if (fuente === 'Idealista') {
  const lines = body.split('\n').map(l => l.trim()).filter(Boolean);
  for (let i = 1; i < lines.length; i++) {
    const pm = lines[i].match(/(\d[\d.]+)\s*€/);
    if (pm && lines[i-1].length > 5 && lines[i-1].length < 100) {
      pisos.push({ titulo: lines[i-1], precio: pm[1] + ' €', fuente, fecha });
    }
  }
}

return { json: { pisos: pisos } };
